export function createInitialGameState(lives) {
    return {
        levelIndex: 0,
        score: 0,
        lives,
        collectedInfotrons: 0,
        requiredInfotrons: 0,
        elapsedTicks: 0,
        remainingSeconds: 0,
        status: "start",
        bombSupply: 0,
        deathDelayTicks: null,
    };
}
